export type Cell = [number, number];

const key = (cell: Cell): string => `${cell[0]},${cell[1]}`;

const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
  neighbors === 3 || (isAlive && neighbors === 2);

const neighborCounts = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        const k = key(neighbor);
        const entry = counts.get(k);
        if (entry) {
          entry.count++;
        } else {
          counts.set(k, { cell: neighbor, count: 1 });
        }
      }
    }
  }
  return counts;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(key));
  const counts = neighborCounts(cells);
  const result: Cell[] = [];
  for (const [k, { cell, count }] of counts) {
    if (livesNextGeneration(liveKeys.has(k), count)) {
      result.push(cell);
    }
  }
  return result;
}

export type Cell = [number, number];

const key = (cell: Cell): string => `${cell[0]},${cell[1]}`;

const isNeighbor = (a: Cell, b: Cell): boolean =>
  (a[0] !== b[0] || a[1] !== b[1]) &&
  Math.abs(a[0] - b[0]) <= 1 &&
  Math.abs(a[1] - b[1]) <= 1;

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
  neighbors === 3 || (isAlive && neighbors === 2);

const candidateCells = (cells: Cell[]): Cell[] => {
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        candidates.set(key(candidate), candidate);
      }
    }
  }
  return [...candidates.values()];
};

const survives = (cell: Cell, liveKeys: Set<string>, cells: Cell[]): boolean =>
  livesNextGeneration(liveKeys.has(key(cell)), countNeighbors(cell, cells));

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(key));
  return candidateCells(cells).filter((cell) => survives(cell, liveKeys, cells));
}

export type Cell = [number, number];

const key = ([x, y]: Cell): string => `${x},${y}`;

const isNeighbor = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
  (ax !== bx || ay !== by) && Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;

const countNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
  neighbors === 3 || (isAlive && neighbors === 2);

const candidateCells = (cells: Cell[]): Cell[] => {
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const candidate: Cell = [x + dx, y + dy];
        candidates.set(key(candidate), candidate);
      }
    }
  }
  return [...candidates.values()];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(key));
  return candidateCells(cells).filter((cell) =>
    livesNextGeneration(liveKeys.has(key(cell)), countNeighbors(cell, cells))
  );
}
